  ('aboriginal-f0899a01-moex-00207', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '關於妨害秘密罪，下列敘述何者錯誤？', '["未得他人同意，以肉眼偷窺他人洗澡者，構成刑法第315條之1窺視罪", "無故開拆他人內為銀行帳單之封緘信函者，構成刑法第315條妨害書信秘密罪", "以光照方式透視而窺視他人封緘信函之內容者，構成刑法第315條妨害書信秘密罪", "未得他人同意，以智慧型手機拍攝他人短裙下之臀部者，構成刑法第315條之1竊錄罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00208', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '下列情形中，何種誹謗行為之手段不構成刑法第310條第2項之加重誹謗罪？', '["將誹謗內容刊登於報紙", "將誹謗內容於公開播送之廣播節目中口頭說明", "將誹謗內容繪製為諷刺漫畫", "將誹謗內容以文字發表於公開之網路社群媒體"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00209', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '依實務見解，下列何種情況不屬於窺視竊聽竊錄罪中的「非公開活動、言論、談話或身體隱私部位」？', '["在捷運上用手機偷拍偶遇影星的照片", "在高鐵上用手機偷錄女性裙底風光", "使用GPS紀錄器記錄配偶3個月車輛行駛的路線", "使用無人機從高處拍攝他人在住家的內部活動"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00210', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '關於竊盜罪，下列敘述何者錯誤？', '["竊盜罪係以他人之動產及不動產為行為客體", "在百貨公司試穿皮鞋後，將皮鞋穿走據為己有，成立竊盜罪", "甲未得同意而取走他人之雞，再予以殺害而食用，成立竊盜罪", "甲未得友人乙之同意，盜打乙的行動電話，不成立竊盜罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00211', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲、乙兩人一同進入百貨公司，見某收銀臺無人看守，由乙把風，甲將收銀機中之千元大鈔取走。關 於甲之行為，下列敘述何者正確？', '["成立普通竊盜罪", "成立加重竊盜罪", "成立普通搶奪罪", "成立加重搶奪罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00212', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲在公園內見一婦女手提名牌皮包而上前搶奪，得手後隨即逃跑。乙聽見婦女呼救，便奮勇追捕而與 甲發生扭打，甲為保有該皮包，遂將乙打昏而帶著皮包離去。關於甲之行為，下列敘述何者正確？', '["成立刑法第328條強盜罪", "成立刑法第329條準強盜罪", "成立刑法第326條加重搶奪罪", "成立刑法第330條加重強盜罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00213', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '鄰人有貓，十分可愛。甲返家，見鄰人飼養之貓走失竟跑來自宅中，被樹叢絆住無法掙脫，甲救下小 貓，並將該貓據為己有。關於甲之行為，下列何者正確？', '["不成立犯罪", "成立竊盜罪", "成立侵占遺失物罪", "成立贓物罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00214', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲擔任快遞人員，運送包裹至某公益基金會的過程中，起了貪念而取走該包裹，未將該包裹交付該基 金會。依實務見解，甲成立何罪？', '["刑法第321條第1項加重竊盜罪", "刑法第336條第1項公益侵占罪", "刑法第336條第2項業務侵占罪", "刑法第320條第1項竊盜罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00215', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲經過汽車旅館，偶見公司主管乙之車從汽車旅館駛出，乃利用變音器致電乙，佯稱手握乙外遇證據， 並指出何日何時自何汽車旅館出入，要求匯款10萬元，否則將公諸於世。乙驚恐，立刻匯款。關於甲 之行為，下列何者正確？', '["成立偽造文書罪", "成立搶奪罪", "成立竊拍竊錄罪", "成立恐嚇取財罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00216', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '下列行為，何者不構成刑法第358條非法侵入電腦罪？', '["無故輸入他人帳號密碼", "無故利用電腦系統之漏洞", "無故使用他人未設定密碼之電腦", "無故破解使用電腦之保護措施"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
